class Solution {
    public int findBestValue(int[] arr, int target) {
        int minDiff = Integer.MAX_VALUE;
        int result = 0;
        int maxVal = 0;
        for (int num : arr) {
            maxVal = Math.max(maxVal, num);
        }
        for (int i = 1; i <= maxVal; i++) {
            int sum = 0;
            for (int num : arr) {
                sum += Math.min(num, i);
            }
            int diff = Math.abs(target - sum);
            if (diff < minDiff) {
                minDiff = diff;
                result = i;
            } else if (diff == minDiff) {
                result = Math.min(result, i);
            }
        }
        return result;
    }
}
